parameters.jsCode:
const src = $node['Code: Session + Dedupe + 24h'].json || {};

const senderId    = String(src.senderId || '').trim();
const messageId   = String(src.messageId || '').trim();
const now         = Number(src.now || Date.now());
const isDuplicate = !!src.isDuplicate;

const session = src.session || { hasGreeted: false, stage: 'info', lead: { name: '', dni: '', phone: '' } };
session.stage = String(session.stage || 'info');
session.lead  = session.lead || { name: '', dni: '', phone: '' };

const text = String(src.text || '').trim();

// ====================== Normalización base ======================
const stripAccents = (s) =>
  String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const norm = (s) =>
  stripAccents(String(s || '').toLowerCase())
    .replace(/\s+/g, ' ')
    .trim();

// ====================== KB (COMPLETO) ======================
const kbRaw = $node['HTTP Request1'].json || {};
const sigurban = (kbRaw && typeof kbRaw === 'object') ? kbRaw : {};

// ====================== Normalization.synonyms ======================
const applySynonyms = (inputText, normalization) => {
  let s = String(inputText || '');
  const syns = normalization?.synonyms;
  if (!Array.isArray(syns)) return s;

  const escapeRe = (x) => String(x).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

  for (const entry of syns) {
    const to = String(entry?.to || '').trim();
    const fromArr = entry?.from;
    if (!to || !Array.isArray(fromArr)) continue;

    for (const from of fromArr) {
      const f = String(from || '').trim();
      if (!f) continue;
      const re = new RegExp(`\\b${escapeRe(f)}\\b`, 'gi');
      s = s.replace(re, to);
    }
  }
  return s;
};

const textNormalized = applySynonyms(text, sigurban.normalization);
const lcPlain = norm(textNormalized);

// ====================== DB Load ======================
const load = $node['MySQL: Load Context (Session+History+Lead)'].json || {};

// ====================== History ======================
let history = load.history ?? [];
if (typeof history === 'string') {
  try { history = JSON.parse(history); } catch (e) { history = []; }
}
if (!Array.isArray(history)) history = [];
history = history.slice().reverse().slice(-12).map(m => ({ role: m.role, text: String(m.text || '') }));

// ====================== Helpers ======================
const includesAny = (hay, arr) => Array.isArray(arr) && arr.some(k => hay.includes(k));

const listIncludesNormalized = (hayLcPlain, list) => {
  if (!Array.isArray(list)) return false;
  return list.some(x => {
    const t = norm(x);
    return t && hayLcPlain.includes(t);
  });
};

// Botones / respuestas cortas típicas (no son nombre)
const isQuickReplyLike =
  /^(la\s+)?ubicacion$/.test(lcPlain) ||
  /^(los\s+)?requisitos$/.test(lcPlain) ||
  /^precio(s)?$/.test(lcPlain) ||
  /^cuota(s)?$/.test(lcPlain) ||
  /^prima$/.test(lcPlain) ||
  /^plazo$/.test(lcPlain) ||
  /^ok(ay|ey|i)?$/.test(lcPlain) ||
  /^gracias$/.test(lcPlain) ||
  /^(si|sí|no|nel|nop)$/.test(lcPlain) ||
  /^quiero\s+precalific(ar|arme|acion|ación)?$/.test(lcPlain) ||
  /^precalific(ar|arme|acion|ación)$/.test(lcPlain);

// ====================== Policy triggers from KB ======================
const policy = sigurban?.conversationPolicy || {};
const wantsHandoff = listIncludesNormalized(lcPlain, policy.handoffTriggers);
const stopDataCollection = listIncludesNormalized(lcPlain, policy.stopDataCollectionTriggers);

// ---------- DNI ----------
const extractDni = (t) => {
  const s = String(t || '');

  const reA = /\b(\d{4}[-\s]?\d{4}[-\s]?\d{5})\b/;
  const reB = /\b(\d{13})\b/;

  let m = s.match(reA);
  if (m && m[1]) return { digits: m[1].replace(/[^0-9]/g, ''), raw: m[0] };

  m = s.match(reB);
  if (m && m[1]) return { digits: m[1], raw: m[0] };

  return { digits: '', raw: '' };
};

// ---------- PHONE ----------
const extractPhone = (t) => {
  const s = String(t || '');

  const re1 = /\b(?:\+?504[-\s]?)?(\d{4})[-\s]?(\d{4})\b/g;
  const cands = [];
  let m;
  while ((m = re1.exec(s)) !== null) {
    const d = String(m[1] || '') + String(m[2] || '');
    if (d.length === 8) cands.push({ digits: d, raw: m[0] });
  }

  const re2 = /\b(?:\+?504[-\s]?)?(\d{8})\b/;
  const m2 = s.match(re2);
  if (m2 && m2[1] && m2[1].length === 8) cands.push({ digits: m2[1], raw: m2[0] });

  return cands.length ? cands[cands.length - 1] : { digits: '', raw: '' };
};

// ---------- NAME ----------
const NAME_LOCATION_WORDS = [
  'tegucigalpa','siguatepeque','san pedro sula','sps','comayagua','la ceiba','choloma','el progreso','danli','danlí','juticalpa','choluteca','roatan','roatán','copan','copán','olancho','yoro','cortes','cortés','atlantida','atlántida','intibuca','intibucá','valle','colon','colón','francisco morazan','francisco morazán','honduras','usa','eeuu','estados unidos','miami','houston','dallas','new york','nueva york','los angeles','florida','texas','california','madrid','barcelona','espana','españa'
];

const NAME_CONTEXT_WORDS = [
  'casa','casas','construida','construidas','proyecto','proyectos','precio','precios','cuota','cuotas','prima','plazo','financiamiento','credito','crédito','requisito','requisitos','ubicacion','ubicación','direccion','dirección','mapa','whatsapp','asesor','asesora','precalificar','precalificacion','precalificación','aplicar','solicitar','informacion','información','terreno','lote','lotes','visita','visitar','dato','datos','enviar','envia','envía','envio','envío','enviado','enviados','enviaron','mandar','mandalo','mándalo','reenviar','reenvio','reenvío','reenviado','reintentar','reintento','registro','registrado','registrada','crm','sistema'
];

const escapeRegExp = (x) => String(x).replace(/[|\\{}()[\]^$+*?.]/g, '\\$&');
const locationRegex = new RegExp('\\b(' + NAME_LOCATION_WORDS.map(escapeRegExp).join('|') + ')\\b', 'i');
const contextRegex = new RegExp('\\b(' + NAME_CONTEXT_WORDS.map(escapeRegExp).join('|') + ')\\b', 'i');

const BAD_NAME_PHRASE_PATTERNS = [
  /\b(casa|casas|vivienda|viviendas|proyecto|proyectos|lote|lotes|terreno|terrenos)\b/i,
  /\b(ya|si|sí|no|ok|okay|oki|bueno|pero|entonces|mira|gracias|listo|perfecto)\b/i,
  /\b(es|son|esta|está|estan|están|hay|tiene|tienen|tengo|tenemos|incluye|incluyen)\b/i,
  /\b(dato|datos|enviar|envia|envía|envio|envío|enviado|enviados|enviaron|mandar|mandalo|mándalo|reenviar|reenvio|reenvío|reenviado|reintentar|reintento|registro|registrar|registrado|registrada|crm|sistema)\b/i,
  /\b(precio|precios|cuota|cuotas|prima|plazo|requisito|requisitos|ubicacion|ubicación|direccion|dirección|whatsapp|asesor|asesora|precalificar|precalificacion|precalificación)\b/i
];

const startsLikeChatControl = (plain) =>
  /^(ok|okay|oki|bueno|pero|entonces|mira|gracias|listo|perfecto|si|sí|no)\b/i.test(plain);

const cleanNameCandidate = (s) => String(s || '')
  .replace(/https?:\/\/\S+/gi, ' ')
  .replace(/#[A-Za-z0-9_]+/g, ' ')
  .replace(/[0-9]/g, ' ')
  .replace(/[-_]/g, ' ')
  .replace(/[^A-Za-zÁÉÍÓÚÑÜáéíóúñü\s']/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const hasNameStopContext = (cand) => {
  const cPlain = norm(cand);
  return (
    startsLikeChatControl(cPlain) ||
    BAD_NAME_PHRASE_PATTERNS.some((re) => re.test(cPlain)) ||
    /(^|\s)(soy de|vivo en|resido en|estoy en|desde|radico en)(\s|$)/i.test(cPlain) ||
    locationRegex.test(cPlain) ||
    contextRegex.test(cPlain)
  );
};

const looksLikeName = (cand) => {
  if (!cand) return false;

  const cPlain = norm(cand);

  const blocked =
    /(^(si|sí|no|ok(ay|ey|i)?|gracias|dale|de acuerdo|perfecto|listo)$)/i.test(cPlain) ||
    /(^|\s)(quiero|deseo|necesito|me interesa|solo|solamente|info|informacion|información)(\s|$)/i.test(cPlain) ||
    /(^|\s)(precal|precalific|precalificacion|precalificación|calific|aplic|aplicar|solicit|solicitud|credito|crédito|financ|visita|cita|contact|llamar)(\s|$)/i.test(cPlain) ||
    /(^|\s)(donde|dónde|ubicacion|ubicación|ubicad|mapa|direccion|dirección|llegar|como llegar|cómo llegar|requisitos?|precio|cuotas?|prima|plazo|whatsapp|sigurban|landing|galeria|galería|asesora|asesor)(\s|$)/i.test(cPlain) ||
    /(^|\s)(soy de|vivo en|resido en|estoy en|radico en)(\s|$)/i.test(cPlain);

  if (blocked || hasNameStopContext(cPlain)) return false;

  if (cand.length < 6 || cand.length > 60) return false;

  const parts = cand.split(' ').filter(Boolean);
  if (parts.length < 2 || parts.length > 5) return false;
  if (parts.some(w => stripAccents(w).length < 2)) return false;
  if (parts.some(w => /^([a-záéíóúñü])\1{2,}$/i.test(w))) return false;
  if (parts.some(w => BAD_NAME_PHRASE_PATTERNS.some((re) => re.test(norm(w))))) return false;

  const alphaChars = cand.replace(/[^A-Za-zÁÉÍÓÚÑÜáéíóúñü]/g, '');
  if (alphaChars.length < 5) return false;

  return true;
};

const extractNameByPatterns = (rawText) => {
  const t = String(rawText || '');

  const patterns = [
    /(?:mi\s+nombre\s+correcto\s+es)\s+([^\n,.]+)/i,
    /(?:mi\s+nombre\s+completo\s+es)\s+([^\n,.]+)/i,
    /(?:mi\s+nombre\s+es)\s+([^\n,.]+)/i,
    /(?:me\s+llamo)\s+([^\n,.]+)/i,
    /(?:^|\b)(?:no,?\s*)?es\s+([^\n,.]+)/i,
    /(?:soy)\s+([^\n,.]+)/i,
    /(?:nombre\s+completo)\s*[:\-]\s*([^\n,.]+)/i,
    /(?:nombre)\s*[:\-]\s*([^\n,.]+)/i,
  ];

  for (const re of patterns) {
    const m = t.match(re);
    if (m && m[1]) {
      const candidate = cleanNameCandidate(m[1]);
      if (/^(de|desde|en)\s+/i.test(norm(m[1]))) continue;
      if (looksLikeName(candidate)) return candidate;
    }
  }
  return '';
};

const extractNameLoose = (rawText) => {
  const raw = String(rawText || '').trim();
  if (!raw) return '';

  const pieces = raw
    .split(/[\n,;|]+/)
    .map(x => cleanNameCandidate(x))
    .filter(Boolean);

  if (pieces.length > 1) {
    for (const piece of pieces) {
      if (looksLikeName(piece)) return piece;
    }
  }

  const cleaned = cleanNameCandidate(raw);
  if (looksLikeName(cleaned)) return cleaned;
  return '';
};

const nameNeedsReview = (cand) => {
  const c = String(cand || '').trim();
  if (!c) return false;
  const cPlain = norm(c);
  const parts = c.split(' ').filter(Boolean);
  return (
    !looksLikeName(c) ||
    parts.length < 2 ||
    parts.length > 5 ||
    hasNameStopContext(cPlain)
  );
};

// ====================== Intent match from KB (simple) ======================
const matchIntent = (lc, intents) => {
  if (!Array.isArray(intents)) return '';
  let best = null;

  for (const it of intents) {
    const list = it?.match;
    if (!Array.isArray(list)) continue;

    const hits = list.filter(x => {
      const t = norm(x);
      return t && lc.includes(t);
    }).length;

    if (hits <= 0) continue;

    const score = hits + (Number(it?.priority || 0) / 1000);
    if (!best || score > best.score) best = { id: String(it?.id || ''), score };
  }
  return best?.id || '';
};

const matchedIntentId = matchIntent(lcPlain, sigurban.intents);

// ====================== Backward-compatible detectors ======================
const asksRequirements =
  matchedIntentId === 'ASK_REQUIREMENTS' ||
  includesAny(lcPlain, [
    'requisito','requisitos','documento','documentos','documentacion','documentación',
    'papel','papeles','papeleria','papelería',
    'que piden','que necesito','que ocupo','que debo llevar','que tengo que llevar',
    'requisitos para aplicar','requisitos para credito','requisitos para financiamiento'
  ]);

const wantsInfoOnly =
  !!matchedIntentId ||
  includesAny(lcPlain, [
    'precio','precios','cuota','cuotas','mensualidad','pago mensual','cuanto cuesta','cuánto cuesta',
    'cuanto vale','cuánto vale','valor','costo','coste',
    'prima','enganche','inicial','plazo','años','financiamiento','financiar','credito','crédito',
    'ubic','ubicacion','ubicación','donde','dónde','direccion','dirección','referencia',
    'como llegar','cómo llegar','como llego','cómo llego','mapa','waze','google maps',
    'modelo','metros','m2','mt2','habit','habitaciones','cuartos','ban','bañ','baños',
    'foto','fotos','galeria','galería','video','videos','tour'
  ]);

// ======================================================
// ✅ CAMBIO MINIMO: NO disparar precalificación en preguntas de USA/visa/extranjero
// ======================================================
const isForeignQuestion =
  /\b(usa|estados unidos|visa|extranjero|extranjera|españa|espana)\b/i.test(lcPlain);


// ====================== Detección de país/región ======================
const isSpain = /\b(espana|madrid|barcelona|sevilla|valencia|bilbao|espanol|espanola)\b/.test(lcPlain);
const isUSA = /\b(estados unidos|usa|eeuu|miami|houston|nueva york|new york|los angeles|dallas|atlanta|chicago|virginia|maryland|california|arizona|texas|florida)\b/.test(lcPlain);
const hasTPS = /\b(tps|estatus temporal|temporary protected|residencia permanente|residente|ciudadano|ciudadana|green card|visa de trabajo|legal|documentado|documentada)\b/.test(lcPlain);
const isUSALegal   = isUSA && hasTPS;
const isUSAUnknown = isUSA && !hasTPS;
const needsReferido = isSpain || isUSAUnknown;

// ====================== Hora Honduras (UTC-6) ======================
const hourHN   = new Date(now - 6 * 3600000).getUTCHours();
const timeOfDay = hourHN < 12 ? 'manana' : hourHN < 18 ? 'tarde' : 'noche';

const wantsPrequalify =
  !isForeignQuestion && (
    matchedIntentId === 'WANTS_PREQUALIFY' ||
    /(precal|precalific|precalificacion|precalificación|calific|calificacion|calificación)/i.test(lcPlain) ||

    // Aplicar/solicitar SOLO si hay intención clara de trámite, no pregunta general:
    /\b(quiero|deseo|me interesa|como|cómo|puedo)\s+(aplicar|solicitar|tramitar)\b/i.test(lcPlain) ||
    /\b(aplicar|solicitar)\s+(credito|crédito|financiamiento|precalificacion|precalificación|prestamo|préstamo)\b/i.test(lcPlain) ||

    /(credito|crédito|financ|hipotec|prestam|préstam|banco|bur(o|ó)|central de riesgo)/i.test(lcPlain) ||
    /(ingres|salario|constancia|cuanto gano|cuánto gano)/i.test(lcPlain) ||
    /(me pueden|podrian|podrían).*(contact|llamar|asesor|asesora)/i.test(lcPlain) ||
    /(me contacten|contactenme|contáctenme|llamenme|llámenme|llamame|llámame)/i.test(lcPlain) ||
    /(agendar|agenda|cita|visita|tour|quiero visitar|quiero verla|quiero ver la casa)/i.test(lcPlain) ||
    /(me interesa).*(financ|credito|crédito|comprar)/i.test(lcPlain)
  );

const stopPrequalify =
  stopDataCollection ||
  /(no precalificar|no aplicar|no autoriz|no enviar|olvidalo|olvídalo|cancelar|ya no)/i.test(lcPlain) ||
  /(prefiero hablar con persona|prefiero un asesor|prefiero una asesora)/i.test(lcPlain);

// ====================== Parse DNI / Phone / Name ======================
const dniObj = extractDni(text);
let textNoDni = text;
if (dniObj.raw) textNoDni = textNoDni.replace(dniObj.raw, ' ');

const phoneObj = extractPhone(textNoDni);
let textNoDniPhone = textNoDni;
if (phoneObj.raw) textNoDniPhone = textNoDniPhone.replace(phoneObj.raw, ' ');

if (dniObj.digits && dniObj.digits.length === 13) session.lead.dni = dniObj.digits;
if (phoneObj.digits && phoneObj.digits.length === 8) session.lead.phone = phoneObj.digits;

let requiresNameReview = false;
if (session.lead.name && nameNeedsReview(session.lead.name)) {
  requiresNameReview = true;
  session.lead.name = '';
}

const nameEmpty = !String(session.lead.name || '').trim();

if (nameEmpty && !isQuickReplyLike) {
  const byPattern = extractNameByPatterns(text);
  if (byPattern) { session.lead.name = byPattern; requiresNameReview = false; }
}

if (!String(session.lead.name || '').trim() && !isQuickReplyLike) {
  const hasDniOrPhone = !!(dniObj.digits || phoneObj.digits);
  const candidateSource = hasDniOrPhone ? textNoDniPhone : text;
  const loose = extractNameLoose(candidateSource);
  if (loose) { session.lead.name = loose; requiresNameReview = false; }
}

if (!String(session.lead.name || '').trim()) {
  for (let i = history.length - 1; i >= 0; i--) {
    const h = history[i];
    if (h?.role !== 'user') continue;

    const ht = String(h.text || '');
    const hdni = extractDni(ht);
    let hNoDni = ht;
    if (hdni.raw) hNoDni = hNoDni.replace(hdni.raw, ' ');
    const hphone = extractPhone(hNoDni);
    let hNoDniPhone = hNoDni;
    if (hphone.raw) hNoDniPhone = hNoDniPhone.replace(hphone.raw, ' ');

    const byPattern = extractNameByPatterns(ht);
    if (byPattern) { session.lead.name = byPattern; requiresNameReview = false; break; }

    const loose = extractNameLoose(hNoDniPhone);
    if (loose) { session.lead.name = loose; requiresNameReview = false; break; }
  }
}

if (session.lead.name && nameNeedsReview(session.lead.name)) {
  requiresNameReview = true;
  session.lead.name = '';
}

// ====================== nameConfidence (sin IA) ======================
let nameConfidence = 'none'; // none|low|medium|high
const nm = String(session.lead.name || '').trim();
if (nm) {
  const parts = nm.split(' ').filter(Boolean);
  const plain = norm(nm);
  const hasBadTokens = hasNameStopContext(plain);

  if (!hasBadTokens && parts.length >= 2 && parts.length <= 4) nameConfidence = 'high';
  else if (!hasBadTokens && parts.length >= 2 && parts.length <= 5) nameConfidence = 'medium';
  else nameConfidence = 'low';
}

const nameValidation = {
  candidate: nm,
  isValidForCrm: !!nm && !requiresNameReview && (nameConfidence === 'high' || nameConfidence === 'medium') && looksLikeName(nm),
  confidence: nameConfidence,
  requiresNameReview,
  reason: !nm
    ? 'missing_name'
    : requiresNameReview
      ? 'suspicious_or_not_person_name'
      : (nameConfidence === 'low' || nameConfidence === 'none')
        ? 'low_confidence'
        : 'valid_person_name',
  rules: 'Nombre de persona real: 2-5 palabras, sin ubicaciones, frases del proyecto, preguntas, CRM, envío, registro, ni respuestas cortas.'
};

if (!nameValidation.isValidForCrm && session.lead.name) {
  session.lead.name = '';
  nameValidation.candidate = '';
}

// ====================== Lead status from DB ======================
const leadStatusRaw = {
  found: Number(load.lead_found || 0) === 1,
  status: String(load.lead_status || ''),
  name: String(load.lead_name_db || ''),
  dni: String(load.lead_dni_db || ''),
  phone: String(load.lead_phone_db || ''),
  requestedCount: Number(load.requested_count || 0),
  firstRequestedMs: Number(load.first_requested_ms || 0),
  lastRequestedMs: Number(load.last_requested_ms || 0),
  lastReason: String(load.last_reason || ''),
  lastApiResponse: String(load.last_api_response || '')
};

const leadNameDbValid = !!(leadStatusRaw.name.trim() && looksLikeName(leadStatusRaw.name) && !nameNeedsReview(leadStatusRaw.name));
const hasAllDb  = !!(leadNameDbValid && leadStatusRaw.dni.trim() && leadStatusRaw.phone.trim());
const isSent    = /sent|submitted|contacted|enviado/i.test(leadStatusRaw.status);
const isPending = /pending|sending|in_flight|proces|queue/i.test(leadStatusRaw.status);

const leadSent = !!(leadStatusRaw.found && hasAllDb && isSent);
const leadInFlight = !!(
  leadStatusRaw.found &&
  hasAllDb &&
  isPending &&
  leadStatusRaw.lastRequestedMs &&
  (now - leadStatusRaw.lastRequestedMs < 10 * 60 * 1000)
);

const leadStatus = {
  ...leadStatusRaw,
  leadHasAllFields: hasAllDb,
  leadNameDbValid,
  leadSent,
  leadInFlight
};

// ====================== Missing fields (desde KB) ======================
const fieldsOrder = Array.isArray(sigurban?.leadCapture?.fieldsOrder)
  ? sigurban.leadCapture.fieldsOrder
  : ['name', 'dni', 'phone'];

const missing = [];
for (const f of fieldsOrder) {
  if (f === 'name'  && !nameValidation.isValidForCrm) missing.push('name');
  if (f === 'dni'   && !String(session.lead.dni   || '').trim()) missing.push('dni');
  if (f === 'phone' && !String(session.lead.phone || '').trim()) missing.push('phone');
}
const nextMissing = missing[0] || '';

// ====================== Consent ======================
const isNameCorrection =
  /^(no,?\s*)?(es|mi nombre correcto es|mi nombre completo es|mi nombre es|me llamo|soy)\s+[a-záéíóúñü]/i.test(lcPlain);

const consentNo =
  !isNameCorrection &&
  /(^(no|nel|nop|negativo)\b|no gracias|prefiero whatsapp|mejor whatsapp|mejor por whatsapp|mejor por wpp|mejor por wasap|no autoriz|no lo envies|no lo envie|no enviar|despues|después|luego|mas tarde|más tarde|otro dia|otro día)/i.test(lcPlain);

const consentYes =
  !consentNo && /(^(si|sí)\b|claro\b|dale\b|de una\b|va\b|ok(ay|ey|i)?\b|perfecto\b|listo\b|de acuerdo\b|autorizo\b|te autorizo\b|acepto\b|confirmo\b|proced(e|a)\b|envi(a|á|e)\b|mand(a|á|e)\b)/i.test(lcPlain);

// ====================== Collecting Gate (solo si el usuario lo activó) ======================
// Si no existe, por defecto NO está habilitado
if (typeof session.collectingEnabled !== 'boolean') {
  session.collectingEnabled = false;
}

// Si el usuario expresa intención de precalificar, habilitamos collecting
if (wantsPrequalify) {
  session.collectingEnabled = true;
}

// Si el usuario detiene precalificación, deshabilitamos collecting
if (stopPrequalify) {
  session.collectingEnabled = false;
}

const collectingEnabled = session.collectingEnabled === true;

// ====================== Stage logic (prioridades) ======================
const hasAnyLead =
  !!String(session.lead?.name || '').trim() ||
  !!String(session.lead?.dni || '').trim() ||
  !!String(session.lead?.phone || '').trim();

if (leadSent) session.stage = 'submitted';
else if (leadInFlight) session.stage = 'in_flight';
else if (wantsHandoff) session.stage = 'handoff';
else {
  // Si el usuario pidió parar y no hay datos, volvemos a info
  if (stopPrequalify && !hasAnyLead) session.stage = 'info';

  // Solo entramos a collecting si collectingEnabled está activo
  if (collectingEnabled && !['collecting', 'awaiting_consent'].includes(session.stage)) {
    session.stage = 'collecting';
