  !leadSent &&
  !leadInFlight &&
  missing.length === 0 &&
  session.stage === 'awaiting_consent' &&
  !consentYes &&
  !consentNo;

const leadReady =
  collectingEnabled &&
  !leadSent &&
  !leadInFlight &&
  missing.length === 0 &&
  ['awaiting_consent', 'collecting'].includes(String(session.stage || '')) &&
  consentYes;

// ====================== Output ======================
