const text = String(base.text || '').trim();
const textNormalized = String(base.textNormalized || text).trim();

const norm = (s) => String(s || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[̀-ͯ]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

