const pickTemplate = (arr, fallback) => {
  if (Array.isArray(arr) && arr.length) return String(arr[Math.floor(Math.random() * arr.length)]);
  return String(fallback || '').trim();
};

// Fallback ask messages — primera vez pidiendo el dato
const askMapFallback = {
  name:  '¿Me compartís tu nombre completo?',
  dni:   '¿Me compartís tu DNI (13 dígitos, con o sin guiones)?',
  phone: '¿Me compartís tu número de teléfono (8 dígitos)?'
