const askForField = (field, soft) => {
  const map = soft ? askMapSoft : askMapFallback;
  if (field === 'name')  return pickTemplate(templates.ask_name,  map.name);
  if (field === 'dni')   return pickTemplate(templates.ask_dni,   map.dni);
