const formatReq = (req) => {
  if (!req) return '';
  if (Array.isArray(req)) return req.map(x => '• ' + String(x).trim()).join('\n');
  if (typeof req === 'object') {
    return Object.entries(req).map(([k, v]) => {
      if (Array.isArray(v)) return `• ${k}:\n` + v.map(x => `   - ${String(x).trim()}`).join('\n');
