const consentNo    = base.consentNo  === true;
const wantsHandoff = base.wantsHandoff === true || String(session.stage || '') === 'handoff';

// -------- Nuevos flags de país y hora --------
const isSpain       = base.isSpain     === true;
const isUSALegal    = base.isUSALegal  === true;
