const needsReferido = base.needsReferido === true;
const timeOfDay     = String(base.timeOfDay || 'dia');

// -------- Anti-repetición: detectar qué pidió el bot recientemente --------
const recentBotTexts = (base.history || [])
  .filter(h => h.role === 'assistant')
  .slice(-3)
