const alreadyAskedName  = recentBotTexts.some(t => /nombre completo/i.test(t));
const alreadyAskedDni   = recentBotTexts.some(t => /\bdni\b|c[eé]dula|identidad/i.test(t));
const alreadyAskedPhone = recentBotTexts.some(t => /tel[eé]fono|celular|\btel\b/i.test(t));

const fieldAlreadyAsked = (field) =>
  (field === 'name'  && alreadyAskedName)  ||
  (field === 'dni'   && alreadyAskedDni)   ||
