// -------- Referido message --------
const buildReferidoMsg = () =>
  pickTemplate(
    templates.referido_option,
    '\n\nTambién existe una alternativa: si tenés un familiar o persona de confianza en Honduras, ellos pueden tramitar el crédito y coordinar el pago con vos 😊\n\n¿Te cuento más sobre esa opción?'
  );

// -------- CADENA DE PRIORIDADES --------

// 1) Lead ya enviado
if (leadSent) {
  session.stage = 'submitted';
  reply = pickTemplate(
    templates.closing_submitted,
    '¡Listo! Ya registré tu información para precalificación 🏡 En breve una asesora te contacta.\nSi querés seguimiento inmediato: #FBSIGURBAN\nhttps://www.sigurban.com/FBSIGURBAN'
