const base = $node['Code: Guardrail Collecting Reply'].json;
const session = base.session || { stage: 'awaiting_consent', lead: { name: '', dni: '', phone: '' } };
const api = $json || {};

const parseMaybeJson = (value) => {
  if (typeof value !== 'string') return value;
  const s = value.trim();
  if (!s) return value;
  try { return JSON.parse(s); } catch (e) {}
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try { return JSON.parse(s.slice(first, last + 1).replace(/\\"/g, '"')); } catch (e) {}
  }
  return value;
};

const pickBody = () => {
  const candidates = [
    api.body,
    api.data,
    api.response?.body,
    api.response?.data,
    api.json,
    api.error?.response?.body,
    api.error?.message,
    api.message,
    api
  ];
  for (const value of candidates) {
    const parsed = parseMaybeJson(value);
    if (parsed && typeof parsed === 'object') return parsed;
  }
  return parseMaybeJson(api.body ?? api.data ?? api.error?.message ?? api.message ?? api);
};

const body = pickBody();

const statusCode = Number(
  api.statusCode ||
  api.status ||
  api.response?.statusCode ||
  api.response?.status ||
  api.error?.status ||
  api.error?.statusCode ||
  body?.status ||
  body?.statusCode ||
  0
);

const crmMessage = String(
  body?.message ||
  api.message ||
  api.error?.message ||
  api.response?.message ||
  ''
).trim();

const messageLc = crmMessage.toLowerCase();
const duplicate = /ya existe un prospecto/.test(messageLc) ||
  (messageLc.includes('dni') && messageLc.includes('existe')) ||
  messageLc.includes('duplicate') ||
  messageLc.includes('duplicado');

const okWrapped = body?.ok === true || api.ok === true;
const exists = body?.exists === true || api.exists === true || body?.data?.exists === true || duplicate;

const looksLikeCreatedLead = !!(
  body &&
  typeof body === 'object' &&
  (body._id || body.id || (body.name && body.phone && (body.dni || body.passport || body.residenceNumber)))
);

const explicitFailure = (body?.ok === false || api.ok === false) && !exists;
const transportError = !!api.error && !exists;
const httpError = statusCode >= 400 && !exists;
const success = (okWrapped || exists || looksLikeCreatedLead || (statusCode >= 200 && statusCode < 300 && body && typeof body === 'object')) &&
  !explicitFailure &&
  !transportError &&
  !httpError;

const crmDebug = {
  endpoint: 'https://api.crm.sigurban.com/api/leads/chatbot',
  statusCode,
  okWrapped,
  exists,
  duplicate,
  looksLikeCreatedLead,
  explicitFailure,
  transportError,
  httpError,
  message: crmMessage,
  body
};

let leadRequestStatus = 'error';
let leadRequestReason = 'api_error';

if (!success) {
  if (statusCode) leadRequestReason = 'api_error_http_' + statusCode;
  if (explicitFailure) leadRequestReason = 'api_error_ok_false';
  if (transportError) leadRequestReason = 'api_error_transport';
