const base = JSON.parse(JSON.stringify($node['Code: Context + Lead + Stage'].json || {}));
const raw = $json || {};

function pickFirstString(...candidates) {
  for (const c of candidates) {
    if (typeof c === 'string' && c.trim()) return c.trim();
  }
  return '';
}

function extractModelText(value) {
  const out0 = value?.output?.[0];
  const c0 = out0?.content?.[0];
  return pickFirstString(
    value?.text,
    value?.output_text,
    value?.response?.text,
    out0?.text,
    out0?.output_text,
    c0?.text,
    c0?.value,
    c0?.output_text,
    c0?.annotations?.logprobs?.[0]?.text,
    c0?.annotations?.logprobs?.text
  );
}

function parseJsonObject(text) {
  const s = String(text || '').trim();
  if (!s) return null;
  try { return JSON.parse(s); } catch (e) {}
  const match = s.match(/\{[\s\S]*\}/);
  if (!match) return null;
  try { return JSON.parse(match[0]); } catch (e) { return null; }
}

const stripAccents = (s) => String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const compact = (s) => stripAccents(String(s || '').toLowerCase()).replace(/[^a-zñ]/g, '');

const text = extractModelText(raw);
const parsed = parseJsonObject(text) || {};

const session = base.session || { stage: 'info', lead: { name: '', dni: '', phone: '' } };
session.lead = session.lead || { name: '', dni: '', phone: '' };

const deterministic = base.nameValidation || {};
const candidate = String(session.lead.name || '').trim();
const normalized = String(parsed.normalized_name || candidate).trim();
const aiConfidence = String(parsed.confidence || '').toLowerCase();
const aiReturnedBoolean = typeof parsed.is_person_name === 'boolean';
const aiAccepts = parsed.is_person_name === true && ['high', 'medium'].includes(aiConfidence) && !!normalized;
const aiRejects = parsed.is_person_name === false;
const deterministicAccepts = deterministic.isValidForCrm === true;

const similarEnough =
  !candidate ||
  !normalized ||
  compact(candidate) === compact(normalized) ||
  compact(candidate).includes(compact(normalized)) ||
  compact(normalized).includes(compact(candidate));

const aiValidation = {
  rawText: text,
  isPersonName: aiReturnedBoolean ? parsed.is_person_name : null,
  normalizedName: normalized,
  confidence: aiConfidence || 'unknown',
  reason: String(parsed.reason || (raw.error ? 'openai_validation_error' : '')),
  usedFallback: !aiReturnedBoolean
};

const finalNameValid =
  deterministicAccepts &&
  similarEnough &&
  (aiAccepts || (!aiReturnedBoolean && deterministicAccepts));

if (finalNameValid) {
  if (aiAccepts && normalized && similarEnough) session.lead.name = normalized;
  base.nameValidation = {
    ...deterministic,
    candidate: session.lead.name,
    isValidForCrm: true,
    reason: 'valid_person_name_ai_confirmed',
    aiValidation
  };
} else {
  session.lead.name = '';
  base.nameValidation = {
    ...deterministic,
    candidate: '',
    isValidForCrm: false,
    reason: aiRejects ? 'ai_rejected_not_person_name' : (deterministic.reason || 'invalid_name'),
    aiValidation
  };
}

const fieldsOrder = Array.isArray(base.sigurban?.leadCapture?.fieldsOrder)
  ? base.sigurban.leadCapture.fieldsOrder
  : ['name', 'dni', 'phone'];

const missing = [];
for (const f of fieldsOrder) {
  if (f === 'name' && base.nameValidation.isValidForCrm !== true) missing.push('name');
  if (f === 'dni' && !String(session.lead.dni || '').trim()) missing.push('dni');
  if (f === 'phone' && !String(session.lead.phone || '').trim()) missing.push('phone');
}

if (missing.length > 0 && ['awaiting_consent', 'submitted'].includes(String(session.stage || ''))) {
  session.stage = 'collecting';
}
if (missing.length === 0 && session.collectingEnabled === true && !['submitted', 'in_flight'].includes(String(session.stage || ''))) {
  session.stage = 'awaiting_consent';
}

const leadSent = base.leadStatus?.leadSent === true;
const leadInFlight = base.leadStatus?.leadInFlight === true;
base.session = session;
base.missing = missing;
base.nextMissing = missing[0] || '';
base.needsConsentPrompt =
  !leadSent &&
  !leadInFlight &&
  missing.length === 0 &&
  session.stage === 'awaiting_consent' &&
  base.consentYes !== true &&
  base.consentNo !== true;

base.leadReady =
  session.collectingEnabled === true &&
  base.nameValidation.isValidForCrm === true &&
  !leadSent &&
  !leadInFlight &&
  missing.length === 0 &&
  ['awaiting_consent', 'collecting'].includes(String(session.stage || '')) &&
  base.consentYes === true;

base.parsed = {
  ...(base.parsed || {}),
  aiNameValidation: aiValidation
};

return [{ json: base }];
